import { __ } from "@wordpress/i18n";
import {
	InspectorControls,
	useBlockProps,
	useSettings,
} from "@wordpress/block-editor";
import {
	__experimentalUnitControl,
	BaseControl,
	ColorPalette,
	PanelBody,
	SelectControl,
	ToggleControl,
} from "@wordpress/components";
import { useSelect } from "@wordpress/data";
import { useState, useEffect } from "@wordpress/element";
// useState is for adding data variables
// useEffect is for adding effect when rendering on front end (return)
import apiFetch from "@wordpress/api-fetch"; // It doesn't use {}
import "./editor.scss";

export default function Edit({ attributes, setAttributes }) {
	const [colors] = useSettings("color.palette");
	const [postTypesOptions, setPostTypesOptions] = useState([]);
	useEffect(() => {
		apiFetch({
			path: "/wp/v2/types",
		}).then((types) => {
			setPostTypesOptions([
				{
					label: "Select Your Custom Post Type",
					value: "",
				},
				...Object.entries(types)
					.filter(
						([slug]) =>
							slug !== "page" &&
							slug !== "post" &&
							slug !== "attachment" &&
							slug !== "nav_menu_item" &&
							!slug.startsWith("wp_"),
					)
					.map(([slug, type]) => ({
						label: type.name,
						value: slug,
					})),
			]);
		});
	}, []);

	// useEffect for custom field
	const [customFieldsOptions, setCustomFieldsOptions] = useState([]);
	useEffect(() => {
		if (!attributes.postType) {
			setCustomFieldsOptions({
				value: "",
			});
			setAttributes({ customField: "" });
		} else {
			apiFetch({
				path: `/vrda/v1/custom-fields/${attributes.postType}`,
			}).then((fields) => {
				setCustomFieldsOptions(
					fields.flatMap((field) =>
						Object.keys(field).map((slug) => ({
							label: slug,
							value: slug,
						})),
					),
				);
			});
		}
	}, [attributes.postType]);

	const blockProps = useBlockProps({
		className: attributes.itemPosition ? "is-items-vertical" : "",
		style: {
			"--item-background-color": attributes.itemBackgroundColor,
			"--item-border-radius": attributes.itemBorderRadius,
			"--item-padding-block": attributes.itemPaddingBlock,
			"--item-padding-inline": attributes.itemPaddingInline,
			"--item-spacing": attributes.itemSpacing,
		},
	});

	return (
		<>
			<InspectorControls>
				<PanelBody title={__("Settings", "display-custom-field-value")}>
					<SelectControl
						label={__("Post Type", "display-custom-field-value")}
						value={attributes.postType}
						options={postTypesOptions}
						onChange={(postType) => setAttributes({ postType })}
					/>
					<SelectControl
						label={__("Custom Field", "display-custom-field-value")}
						value={attributes.customField}
						options={customFieldsOptions}
						onChange={(customField) => setAttributes({ customField })}
					/>
					<BaseControl
						label={__("Item Position", "display-custom-field-value")}
					>
						<ToggleControl
							label={__("Vertical")}
							help={
								attributes.itemPosition
									? "The items will be displayed vertically"
									: "The items will be displayed horizontally"
							}
							checked={attributes.itemPosition}
							onChange={(itemPosition) => {
								setAttributes({ itemPosition });
							}}
						/>
					</BaseControl>
					<BaseControl
						label={__("Item Background Color", "display-custom-field-value")}
					>
						<ColorPalette
							colors={colors}
							value={attributes.itemBackgroundColor}
							onChange={(color) =>
								setAttributes({ itemBackgroundColor: color })
							}
						/>
					</BaseControl>
					<__experimentalUnitControl
						label={__("Item Padding Block", "display-custom-field-value")}
						value={attributes.itemPaddingBlock}
						onChange={(value) => setAttributes({ itemPaddingBlock: value })}
					/>
					<__experimentalUnitControl
						label={__("Item Padding Inline", "display-custom-field-value")}
						value={attributes.itemPaddingInline}
						onChange={(value) => setAttributes({ itemPaddingInline: value })}
					/>
					<__experimentalUnitControl
						label={__("Item Spacing", "display-custom-field-value")}
						value={attributes.itemSpacing}
						onChange={(value) => setAttributes({ itemSpacing: value })}
					/>
					<__experimentalUnitControl
						label={__("Item Border Radius", "display-custom-field-value")}
						value={attributes.itemBorderRadius}
						onChange={(value) => setAttributes({ itemBorderRadius: value })}
					/>
				</PanelBody>
			</InspectorControls>
			<div {...blockProps}>
				<p>Value Example</p>
				<p>Value Example</p>
			</div>
		</>
	);
}
